import{_ as e,o,c as a,ad as i}from"./chunks/framework.DdcUsuRQ.js";const u=JSON.parse('{"title":"Role intent","description":"The ontology tag attached to each role. Drives forced-colors mapping, APCA targets, WCAG ratio selection, and emitter semantics.","frontmatter":{"title":"Role intent","description":"The ontology tag attached to each role. Drives forced-colors mapping, APCA targets, WCAG ratio selection, and emitter semantics.","head":[["link",{"rel":"canonical","href":"https://studnicky.github.io/iridis/reference/role-schema/intent"}],["meta",{"property":"og:url","content":"https://studnicky.github.io/iridis/reference/role-schema/intent"}],["meta",{"property":"og:title","content":"Role intent: iridis"}],["meta",{"property":"og:description","content":"The ontology tag attached to each role. Drives forced-colors mapping, APCA targets, WCAG ratio selection, and emitter semantics."}],["meta",{"name":"twitter:title","content":"Role intent: iridis"}],["meta",{"name":"twitter:description","content":"The ontology tag attached to each role. Drives forced-colors mapping, APCA targets, WCAG ratio selection, and emitter semantics."}],["meta",{"name":"description","content":"The ontology tag attached to each role. Drives forced-colors mapping, APCA targets, WCAG ratio selection, and emitter semantics."}],["meta",{"property":"article:modified_time","content":"2026-05-17T16:04:29.000Z"}],["meta",{"property":"article:author","content":"Andrew Studnicky"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"iridis\\",\\"item\\":\\"https://studnicky.github.io/iridis/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Reference\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Role Schema\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/role-schema\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":4,\\"name\\":\\"Role intent\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/role-schema/intent\\"}]}"]]},"headers":[],"relativePath":"reference/role-schema/intent.md","filePath":"reference/role-schema/intent.md","lastUpdated":1779033869000}'),r={name:"reference/role-schema/intent.md"};function n(d,t,c,s,l,h){return o(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="role-intent" tabindex="-1">Role intent <a class="header-anchor" href="#role-intent" aria-label="Permalink to &quot;Role intent&quot;">​</a></h1><p>A canonical tag from the <code>ColorIntentType</code> union that says what <em>kind</em> of role this is, independent of its name. Drives every downstream semantic decision: forced-colors token selection, APCA Lc target, WCAG required-ratio, Capacitor <code>StatusBar</code> style.</p><h2 id="allowed-values" tabindex="-1">Allowed values <a class="header-anchor" href="#allowed-values" aria-label="Permalink to &quot;Allowed values&quot;">​</a></h2><p>The intent vocabulary is closed at 10 members, grouped by usage family.</p><h3 id="core-ontology" tabindex="-1">Core ontology <a class="header-anchor" href="#core-ontology" aria-label="Permalink to &quot;Core ontology&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Intent</th><th>Meaning</th></tr></thead><tbody><tr><td><code>text</code></td><td>Primary text content painted over a background.</td></tr><tr><td><code>background</code></td><td>Primary surface that receives a foreground.</td></tr><tr><td><code>accent</code></td><td>Brand or emphasis colour calling attention.</td></tr><tr><td><code>muted</code></td><td>Low-emphasis text or chrome (de-emphasised content).</td></tr></tbody></table><h3 id="signal-family" tabindex="-1">Signal family <a class="header-anchor" href="#signal-family" aria-label="Permalink to &quot;Signal family&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Intent</th><th>Meaning</th></tr></thead><tbody><tr><td><code>critical</code></td><td>Error or danger state signal.</td></tr><tr><td><code>positive</code></td><td>Success or affirmative state signal.</td></tr></tbody></table><h3 id="interaction-family" tabindex="-1">Interaction family <a class="header-anchor" href="#interaction-family" aria-label="Permalink to &quot;Interaction family&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Intent</th><th>Meaning</th></tr></thead><tbody><tr><td><code>link</code></td><td>Anchor text foreground.</td></tr><tr><td><code>button</code></td><td>Actionable surface (button face).</td></tr><tr><td><code>onAccent</code></td><td>Foreground painted onto an accent surface.</td></tr><tr><td><code>onButton</code></td><td>Foreground painted onto a button surface.</td></tr></tbody></table><h2 id="what-it-does" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What it does&quot;">​</a></h2><ul><li><code>EmitCssVars.forcedColorsToken</code> picks the Windows-High-Contrast-Mode system color from the intent. <code>text</code> → <code>CanvasText</code>, <code>background</code> → <code>Canvas</code>, <code>critical</code> → <code>Mark</code>, etc.</li><li><code>EnforceApca</code> selects the Lc target from the intent (60 for normal text intent, 75 for large text, 90 for body text on chromatic accents).</li><li><code>wcagRequiredRatio</code> selects the default minimum contrast ratio (4.5:1 normal, 3:1 large, etc) when a contrast pair doesn&#39;t declare one explicitly.</li><li><code>EmitCapacitorTheme</code> reads <code>background</code> to set the iOS <code>StatusBar</code> style.</li></ul><h2 id="what-it-means" tabindex="-1">What it means <a class="header-anchor" href="#what-it-means" aria-label="Permalink to &quot;What it means&quot;">​</a></h2><p>Intent is orthogonal to role name. Two roles with intent <code>accent</code> are <em>both</em> accents; the schema&#39;s <code>derivedFrom</code> plus <code>hueOffset</code> is the right tool to relate them parametrically. Intent is the <strong>classifier</strong>; <code>name</code> is the <strong>identifier</strong>.</p><h2 id="how-to-author" tabindex="-1">How to author <a class="header-anchor" href="#how-to-author" aria-label="Permalink to &quot;How to author&quot;">​</a></h2><ul><li>Always set an intent on every role. Roles without an intent inherit the <em>role-name-substring-inferred</em> fallback (legacy), which is unstable.</li><li>Use the intent that matches the role&#39;s purpose, not its appearance. A muted-grey role used as quiet body text is <code>text</code>, not <code>muted</code>.</li><li>When introducing a new role family that doesn&#39;t fit the closed ontology, fall back to the closest member rather than inventing a string. The ontology is intentionally small to keep downstream emitters reliable.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../../concepts/role-schemas">Role schemas overview</a>: full authoring guide.</li><li><a href="./contrast-pairs">Contrast pairs</a>: declares which intents pair against which.</li></ul>',18)])])}const p=e(r,[["render",n]]);export{u as __pageData,p as default};
